public class Main {
    public static void main(String[] args) {
        byte  b = 100;
        short s = 30000;
        int   i = 2_000_000;  // underscores for readability!
        long  l = 9_000_000_000L; // L suffix required for long literals
        float  f = 3.14f;     // f suffix required for float
        double d = 3.14159265;
        char   c = 'A';       // single quotes for char
        boolean flag = true;

        System.out.println(b + " " + s + " " + i + " " + l);
        System.out.println(f + " " + d);
        System.out.println(c + " " + flag);
    }
}

public class Main {
    public static void main(String[] args) {
        // BUG: 3 billion overflows int!
        int population = 3_000_000_000; // this line won't compile
        System.out.println(population);

        // Fix: use long
        long safePopulation = 3_000_000_000L;
        System.out.println(safePopulation);
    }
}

public class Main {
    public static void main(String[] args) {
        float  f = 1.23456789f;
        double d = 1.23456789;

        System.out.println(f);  // loses precision!
        System.out.println(d);  // full precision

        // Classic floating-point trap:
        System.out.println(0.1 + 0.2);
        System.out.println(0.1 + 0.2 == 0.3); // false!
    }
}

public class Main {
    public static void main(String[] args) {
        char letter = 'A';
        System.out.println(letter);
        System.out.println((int) letter);  // print as number

        // Arithmetic on chars:
        char next = (char) (letter + 1);
        System.out.println(next); // B

        // Loop through alphabet:
        for (char ch = 'A'; ch <= 'E'; ch++) {
            System.out.print(ch + " ");
        }
        System.out.println();
    }
}

public class Main {
    public static void main(String[] args) {
        int i = 42;
        double d = i;       // widening: int → double (automatic)
        System.out.println(d);

        double pi = 3.99;
        int truncated = (int) pi;  // narrowing: drops decimal (no rounding!)
        System.out.println(truncated);

        // String to int:
        String s = "123";
        int parsed = Integer.parseInt(s);
        System.out.println(parsed + 1);
    }
}

public class Main {
    public static void main(String[] args) {
        String greeting = "Hello, Java!";
        System.out.println(greeting.length());
        System.out.println(greeting.toUpperCase());
        System.out.println(greeting.contains("Java"));
        System.out.println(greeting.replace("Java", "World"));

        // Comparing strings:
        String a = "hello";
        String b = "hello";
        System.out.println(a.equals(b));  // true — content comparison
    }
}

public class Main {
    public static void main(String[] args) {
        // Wrapper class utility methods:
        System.out.println(Integer.MAX_VALUE);
        System.out.println(Integer.MIN_VALUE);
        System.out.println(Integer.parseInt("42"));
        System.out.println(Double.parseDouble("3.14"));

        // Autoboxing:
        Integer boxed = 100;   // autobox: int → Integer
        int unboxed = boxed;   // unbox: Integer → int
        System.out.println(boxed + unboxed);

        // Converting to String:
        System.out.println(String.valueOf(42));
        System.out.println(Integer.toString(255, 16)); // 255 in hex
    }
}
